UPDATE wf_task
SET status = #{status},
    finish_time = NOW()
WHERE instance_id = #{instanceId}
  AND status = 'TODO';

UPDATE wf_task
SET
    status = #{canceledStatus},
    finish_time = NOW()
WHERE node_instance_id = #{nodeInstanceId}
  AND id != #{keepTaskId}
  AND status = #{todoStatus}
